  function cardsForCol(colId) { return cards.filter(c => c.column_id === colId) }

  function cardBorder(card) {
    if (!card.card_date || card.is_todo) return '1px solid var(--border)'
    const shootCol = cols.find(c => c.title === 'Shootings')
    if (!shootCol || card.column_id !== shootCol.id) return '1px solid var(--border)'
    const diffH = (new Date() - new Date(card.card_date + 'T00:00:00')) / 3600000
    if (diffH > 48) return '2px solid #b91c1c'
    if (diffH > 0) return '2px solid #f97316'
    return '1px solid var(--border)'
  }

  async function moveColumn(fromId, toId) {
    const fromCol = cols.find(c => c.id === fromId)
    const toCol = cols.find(c => c.id === toId)
    if (!fromCol || !toCol) return
    // Swap positions
    await supabase.from('columns').update({ position: toCol.position }).eq('id', fromId)
    await supabase.from('columns').update({ position: fromCol.position }).eq('id', toId)
    addLog('Spalte átrendezve: ' + fromCol.title)
    loadCols()
  }

  async function onDrop(e, colId) {
    e.preventDefault()
    document.querySelectorAll('.bcol').forEach(el => { el.style.borderColor = ''; el.style.boxShadow = '' })
    if (!dragging || dragging.column_id === colId) return
    const cardId = dragging.id
    await supabase.from('cards').update({ column_id: colId, updated_at: new Date().toISOString() }).eq('id', cardId)
    addLog('Karte verschoben: ' + dragging.title)
    setDragging(null)
    setDroppedCard(cardId)
    setTimeout(() => setDroppedCard(null), 500)
    loadCards()
  }

